function flashCopyMessage(a,b){a.textContent=b,setTimeout(function(){a.textContent='Copy'},1e3)}function selectText(c){const a=window.getSelection(),b=document.createRange();return b.selectNodeContents(c),a.removeAllRanges(),a.addRange(b),a}function addCopyButton(b){const a=document.createElement("button");a.className="copy-button",a.textContent='Copy';const c=b.firstElementChild;a.addEventListener('click',function(){try{const b=selectText(c);navigator.clipboard.writeText(b),b.removeAllRanges(),flashCopyMessage(a,'Copied!')}catch(b){console&&console.log(b),flashCopyMessage(a,'Failed')}}),b.appendChild(a)}navigator.clipboard&&(window.onload=()=>{const a=document.getElementsByClassName('highlight');for(let b of a)addCopyButton(b)})